def to_negabinary(n):
    if n == 0: return ""
    n, rem = divmod(n, -2)
    if rem < 0:
        n, rem = n + 1, rem + 2
    return to_negabinary(n) + str(rem)

def convert(n):
    return to_negabinary(n) if n != 0 else "0"

if __name__ == "__main__":
    print(f"7 in base -2: {convert(7)}")
